firmware_template.source:
#include "pcm_streamer.h"
#include <WiFi.h>
#include <WebSocketsClient.h>
#include <driver/i2s.h>

#define MIC_WS  4
#define MIC_SCK 5
#define MIC_SD  7
#define SR      16000
#define DMA_LEN 256

static WebSocketsClient _ws;
static bool _connected = false;
static int _chunk = 640;
static int _shift = 11;
static int32_t _hpf_in = 0, _hpf_out = 0;
static uint8_t _pkt[3200];
static int _pkt_len = 0;

static int16_t _proc(int32_t raw) {
    int32_t v = raw >> _shift;
    if (v > 30000) v = 30000; if (v < -30000) v = -30000;
    int32_t s = (int16_t)v;
    int32_t d = s - _hpf_in;
    int32_t o = (_hpf_out * 31785 + d * 31785) >> 15;
    if (o > 32767) o = 32767; if (o < -32768) o = -32768;
    _hpf_in = s; _hpf_out = o;
    return (int16_t)o;
}

static void _ws_event(WStype_t t, uint8_t* p, size_t l) {
    if (t == WStype_CONNECTED) { _connected = true; Serial.println("[pcm] WS connected"); }
    else if (t == WStype_DISCONNECTED) { _connected = false; }
}

void pcm_stream_setup(const char* ssid, const char* pass, const char* ip, int port) {
    WiFi.begin(ssid, pass);
    while (WiFi.status() != WL_CONNECTED) { delay(500); Serial.print("."); }
    Serial.printf("\nWiFi: %s\n", WiFi.localIP().toString().c_str());

    i2s_config_t cfg = {};
    cfg.mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_RX);
    cfg.sample_rate = SR;
    cfg.bits_per_sample = I2S_BITS_PER_SAMPLE_32BIT;
    cfg.channel_format = I2S_CHANNEL_FMT_ONLY_LEFT;
    cfg.communication_format = I2S_COMM_FORMAT_STAND_I2S;
    cfg.dma_buf_count = 8; cfg.dma_buf_len = DMA_LEN;
    cfg.use_apll = true;
    i2s_driver_install(I2S_NUM_0, &cfg, 0, NULL);
    i2s_pin_config_t pins = { .bck_io_num=MIC_SCK, .ws_io_num=MIC_WS, .data_out_num=-1, .data_in_num=MIC_SD };
    i2s_set_pin(I2S_NUM_0, &pins);
    i2s_zero_dma_buffer(I2S_NUM_0);

    _ws.begin(ip, port, "/");
    _ws.onEvent(_ws_event);
    _ws.setReconnectInterval(3000);
    Serial.println("[pcm] streamer ready");
}

void pcm_stream_loop() {
    _ws.loop();
    int32_t raw[DMA_LEN];
    int16_t pcm[DMA_LEN];
    size_t br = 0;
    if (i2s_read(I2S_NUM_0, raw, DMA_LEN * 4, &br, 8) != ESP_OK || !br) return;
    int n = br / 4;
    for (int i = 0; i < n; i++) pcm[i] = _proc(raw[i]);
    if (_connected) {
        int bytes = n * 2;
        if (_pkt_len + bytes > 3200) _pkt_len = 0;
        memcpy(_pkt + _pkt_len, (uint8_t*)pcm, bytes);
        _pkt_len += bytes;
        if (_pkt_len >= _chunk) {
            _ws.sendBIN(_pkt, _pkt_len);
            _pkt_len = 0;
        }
    } else { _pkt_len = 0; }
}

void pcm_stream_set_chunk(int b) { if (b >= 64 && b <= 3200 && b % 2 == 0) _chunk = b; }
void pcm_stream_set_gain(int s)  { if (s >= 10 && s <= 18) _shift = s; }
bool pcm_stream_connected()      { return _connected; }
